import re

def solve(code: list[str], businessLine: list[str], isActive: list[bool]) -> list[str]:
    allowed_businesses = {"electronics", "grocery", "pharmacy", "restaurant"}
    valid = []
    for i in range(len(code)):
        c = code[i]
        bl = businessLine[i]
        a = isActive[i]
        if c and re.fullmatch(r'[a-zA-Z0-9_]+', c) and bl in allowed_businesses and a:
            valid.append((bl, c))
    business_order = {"electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3}
    valid_sorted = sorted(valid, key=lambda x: (business_order[x[0]], x[1]))
    return [x[1] for x in valid_sorted]
